def max_sum(triangle):
    if not triangle:
        return 0
    max_sums = [triangle[0][0]]
    for i in range(1, len(triangle)):
        current_row = triangle[i]
        prev_row = max_sums[-1]
        new_row = []
        for j in range(len(current_row)):
            if j >= len(prev_row):
                max_prev = max(prev_row)
            else:
                max_prev = max(prev_row[:j+1])
            new_sum = max_prev + current_row[j]
            new_row.append(new_sum)
        max_sums.append(new_row)
    return max(max_sums[-1])

# Test cases
assert max_sum([[1], [2,1], [3,3,2]], 3) == 6
assert max_sum([[1], [1, 2], [4, 1, 12]], 3) == 15
assert max_sum([[2], [3,2], [13,23,12]], 3) == 28

